+    // If C = 2^n - 1, then lshr C, X has LSB = 1 when X < n
+    const APInt *CVal;
+    if (match(Src, m_LShr(m_APInt(CVal), m_Value(X))) && (*CVal + 1).isPowerOf2()) {
